// Script Continued Below
// STRY0079375
function onSubmit() {
	try{

		var formAction = '';
		formAction = g_form.getActionName();

		if (formAction == 'Abstain-SendToReview'
			|| formAction == 'Approve-SendToReview' 
			|| formAction == 'ApproveSign-SendToReview' 
			|| formAction == 'ClosedComplete' 
			|| formAction == 'Concur-SendToReview' 
			|| formAction == 'ConcurSign-SendToReview' 
			|| formAction == 'inReview' 
			|| formAction == 'NonConcur-SendToReview' 
			|| formAction == 'NonconcurSign-SendToReview' 
			// STRY0123191
			// || formAction == 'Reject-SendToReview' 
			|| formAction == 'rejectAssignment' 
			|| formAction == 'rejectOUAssignment' 
			|| formAction == 'rework') {

			var task_id = g_form.getUniqueValue();

			var saveMsg = getMessage('Tasker - Modal Save Changes Message');

			var _spModal;
			if(typeof spModal != 'undefined'){
				_spModal = spModal;
			}
			var _spUtil;
			if(typeof spUtil != 'undefined'){
				_spUtil = spUtil;
			}

			if(x_153465_discovert.DTech_Task_Actions==undefined){
				ScriptLoader.getScripts(['x_153465_discovert.DTech_Task_Actions.jsdbx'], function() {
					_requestParameters(task_id, formAction, handleFormAction);
				});
			} else {
				_requestParameters(task_id, formAction, handleFormAction);
			}
			return false;
		}
	}catch(e){
		jslog(e);
		return false;
	}

	function handleFormAction(response){
		var params = {};
		var sParams = response.responseXML.documentElement.getAttribute("answer");
		params = JSON.parse(sParams);

		try{
			var userCancelled = false;
			userCancelled = x_153465_discovert.DTech_Task_Actions.checkChangesAndConfirmChange(_spModal, g_form, saveMsg);
			// stop only if the user cancelled
			if(userCancelled){
				return false;
			}

			switch (formAction) {
				case 'Abstain-SendToReview':
					x_153465_discovert.DTech_Task_Actions.abstain(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'Approve-SendToReview':
					x_153465_discovert.DTech_Task_Actions.approve(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'Concur-SendToReview':
					x_153465_discovert.DTech_Task_Actions.concur(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'NonConcur-SendToReview':
					x_153465_discovert.DTech_Task_Actions.nonconcur(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'ApproveSign-SendToReview': 
					x_153465_discovert.DTech_Task_Actions.approveSign(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'ConcurSign-SendToReview':
					x_153465_discovert.DTech_Task_Actions.concurSign(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'NonconcurSign-SendToReview': 
					x_153465_discovert.DTech_Task_Actions.nonconcurSign(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'rejectAssignment':
					x_153465_discovert.DTech_Task_Actions.rejectAssignment(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'rejectOUAssignment':
					x_153465_discovert.DTech_Task_Actions.rejectOUAssignment(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'inReview':
					x_153465_discovert.DTech_Task_Actions.sendToReview(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'rework':
					x_153465_discovert.DTech_Task_Actions.sendToRework(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				case 'ClosedComplete':
					x_153465_discovert.DTech_Task_Actions.markComplete(_spModal, _spUtil, g_form, params, modalCloseCallback);
					break;
				default:
					break;
			}
			return false;

		}catch(e){
			jslog(e);
			return false;
		}
	}

	//NOTE: this may move out into another file to handle all rest calls from UI Script
	function _requestParameters(task_id, action_name, callback){
		var ajax  = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'getTaskUIActionParamaters');
		ajax.addParam('sysparm_task_id', task_id);
		ajax.addParam('sysparm_action_name', action_name);
		ajax.getXML(callback);
	}

	// STRY0089452, STRY0089339, STRY0089338, STRY0089337, STRY0089336
	function modalCloseCallback(){
		var iframe = this.$window.find("#dialog_frame")[0];
		var iframeWindow = iframe.contentWindow ? iframe.contentWindow :iframe.contentDocument.defaultView;
		var m_form = iframeWindow.g_form;
		if(m_form.modified && confirm(getMessage('Tasker - Modal Save Changes Message'))){
			for (var field in m_form.modifiedFields) {
				var fieldName = field + ''; 
				fieldName = fieldName.substr(fieldName.indexOf('.')+1);
				g_form.setValue(fieldName, m_form.getValue(fieldName));
			}
			g_form.save();
		}

	}
}
